#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int countSquares(vector<vector<int>>& matrix) {
        int m = matrix.size(), n = matrix[0].size();
        vector<vector<int>> dp(n, vector<int>(m));
        int ans = 0;
        for (int j = 0; j < n; j++) {
            dp[j][0] = matrix[0][j];
            ans += dp[j][0];
        }
        for (int i = 1; i < m; i++) {
            dp[0][i] = matrix[i][0];
            ans += dp[0][i];
        }
        for (int j = 1; j < n; j++) {
            for (int i = 1; i < m; i++) {
                if (matrix[i][j] == 1) {
                    dp[j][i] = min({dp[j-1][i], dp[j][i-1], dp[j-1][i-1]}) + 1;
                    ans += dp[j][i];
                }
            }
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n;
    if (!(cin >> m >> n)) return 0;
    vector<vector<int>> matrix(m, vector<int>(n));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (!(cin >> matrix[i][j])) return 0;
        }
    }
    Solution sol;
    int ans = sol.countSquares(matrix);
    cout << ans << '\n';
    return 0;
}
